import React, { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import PaymentModal from '../../components/student/PaymentModal';

export default function StudentDashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [profile, setProfile] = useState(null);
  const [fees, setFees] = useState([]);
  const [loading, setLoading] = useState(true);
  const [payFee, setPayFee] = useState(null);

  const loadData = useCallback(() => {
    Promise.all([axios.get('/students/profile'), axios.get('/fees/my')])
      .then(([p, f]) => { setProfile(p.data); setFees(f.data); })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  if (loading) return <div className="loading-screen" style={{ height: 300, display: 'flex', alignItems: 'center', justifyContent: 'center' }}><div className="spinner" /></div>;

  const paid = fees.filter(f => f.status === 'paid');
  const pending = fees.filter(f => f.status === 'pending' || f.status === 'overdue')
    .sort((a, b) => new Date(a.dueDate) - new Date(b.dueDate));
  const overdue = fees.filter(f => f.status === 'overdue');
  const totalPaid = paid.reduce((s, f) => s + parseFloat(f.totalAmount), 0);
  const totalPending = pending.reduce((s, f) => s + parseFloat(f.totalAmount), 0);
  const fmt = n => `₹${Number(n).toLocaleString('en-IN')}`;
  const nextDue = pending[0];
  const daysUntil = date => Math.ceil((new Date(date) - new Date()) / (1000 * 60 * 60 * 24));

  return (
    <>
      <div className="page-hero">
        <p className="page-hero-label">KEC Student Portal</p>
        <h2>Welcome back, {user?.name?.split(' ')[0]} 👋</h2>
        {profile && (
          <p className="page-hero-meta">
            {profile.studentId} · {profile.department} · Year {profile.year}
            {profile.route && ` · 🚌 Route ${profile.route.routeNumber}`}
          </p>
        )}
      </div>

      {overdue.length > 0 && (
        <div className="alert alert-error">
          <span>⚠️</span>
          <span>You have {overdue.length} overdue fees totaling {fmt(overdue.reduce((s, f) => s + parseFloat(f.totalAmount), 0))}. Pay immediately to avoid service suspension.</span>
        </div>
      )}

      {pending.length > 0 && (
        <div className="pay-banner">
          <div>
            <h3>🚨 Outstanding Balance</h3>
            <p>{fmt(totalPending)} due across {pending.length} pending records</p>
          </div>
          <button className="btn btn-primary" style={{ background: 'white', color: 'var(--primary)', width: 'auto' }} onClick={() => setPayFee(nextDue)}>Pay Now →</button>
        </div>
      )}

      <div className="stats-grid">
        <div className="stat-card green">
          <div className="stat-label">Total Paid</div>
          <div className="stat-value">{fmt(totalPaid)}</div>
          <div className="stat-sub">{paid.length} successful payments</div>
        </div>
        <div className="stat-card red">
          <div className="stat-label">Outstanding</div>
          <div className="stat-value">{fmt(totalPending)}</div>
          <div className="stat-sub">{pending.length} pending installments</div>
        </div>
        <div className="stat-card blue">
          <div className="stat-label">Monthly Rate</div>
          <div className="stat-value">{profile?.route ? fmt(profile.route.monthlyFee) : '—'}</div>
          <div className="stat-sub">Based on Route {profile?.route?.routeNumber}</div>
        </div>
      </div>

      <div className="content-grid">
        <div className="card">
          <div className="card-header"><h3 className="card-title"><span>🚌</span> Transport Details</h3></div>
          <div className="info-list">
            <div className="info-row"><span>Route Number</span><strong>{profile?.route?.routeNumber || '—'}</strong></div>
            <div className="info-row"><span>Boarding Point</span><strong>{profile?.boardingPoint || '—'}</strong></div>
            <div className="info-row"><span>Current Status</span><strong><span className="badge badge-paid">Active</span></strong></div>
            <div className="info-row"><span>Guardian Contact</span><strong>{profile?.parentPhone || '—'}</strong></div>
          </div>
        </div>

        <div className="card">
          <div className="card-header">
            <h3 className="card-title"><span>🕒</span> Recent Fees</h3>
            <button className="btn btn-secondary btn-sm" style={{ padding: '6px 12px', fontSize: 12 }} onClick={() => navigate('/student/fees')}>View All</button>
          </div>
          <div className="table-wrap">
            <table>
              <thead>
                <tr><th>Period</th><th>Amount</th><th>Status</th><th></th></tr>
              </thead>
              <tbody>
                {fees.slice(0, 4).map(f => (
                  <tr key={f.id}>
                    <td><strong>{f.feePeriod || f.feeMonth}</strong></td>
                    <td>{fmt(f.totalAmount)}</td>
                    <td><span className={`badge badge-${f.status}`}>{f.status}</span></td>
                    <td>
                      {(f.status === 'pending' || f.status === 'overdue') && (
                        <button className="btn btn-primary" style={{ padding: '4px 12px', fontSize: 12, width: 'auto' }} onClick={() => setPayFee(f)}>Pay</button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {payFee && (
        <PaymentModal
          fee={payFee}
          onClose={() => setPayFee(null)}
          onSuccess={() => { setPayFee(null); loadData(); }}
        />
      )}
    </>
  );
}
